output_contract.schema:
{
  "source_url": "<string: original content URL>",
  "generated_at": "<string: ISO 8601 timestamp>",
  "content_batch": {
    "linkedin": [
      {
        "post_type": "<string: text | carousel | poll>",
        "content": "<string: post text, max 3000 chars>",
        "hashtags": ["<string>"],
        "hook_line": "<string: first line that appears before 'see more'>",
        "cta": "<string: call to action, or null>",
        "estimated_read_time": "<string: e.g., '30 sec'>"
      }
    ],
    "twitter": [
      {
        "post_type": "<string: single | thread>",
        "tweets": [
          {
            "content": "<string: max 280 chars>",
            "char_count": <integer>
          }
        ],
        "thread_hook": "<string: first tweet that draws people in, or null if single>"
      }
    ],
    "threads": [
      {
        "content": "<string: max 500 chars>",
        "char_count": <integer>
      }
    ]
  },
  "posting_recommendations": {
    "best_time_suggestion": "<string>",
    "spacing_advice": "<string>",
    "a_b_test_ideas": ["<string>"]
  }
}
